from enum import IntEnum
import anthropic

client = anthropic.Anthropic()

class Effort(IntEnum):
    NONE     = 0       # no thinking — fastest, cheapest
    LIGHT    = 2_000   # quick check / short explanation
    STANDARD = 8_000   # multi-step reasoning, code generation
    DEEP     = 32_000  # proofs, adversarial analysis, architecture review

def call(prompt: str, effort: Effort) -> str:
    kwargs = {
        "model": "claude-sonnet-4-6",
        "max_tokens": max(4096, int(effort) + 4096),
        "messages": [{"role": "user", "content": prompt}],
    }
    if effort != Effort.NONE:
        kwargs["thinking"] = {"type": "enabled", "budget_tokens": int(effort)}

    response = client.messages.create(**kwargs)
    return next(b.text for b in response.content if b.type == "text")

# Usage
answer = call("What is the capital of France?", Effort.NONE)
code   = call("Write a merge sort in Python.", Effort.LIGHT)
design = call("Design a rate limiter for a multi-tenant API.", Effort.STANDARD)
audit  = call("Find all SQL injection vectors in this schema: ...", Effort.DEEP)

import re

# Keyword-based heuristic (fast, no API call needed)
DEEP_SIGNALS = [
    r"\b(security audit|penetration|vulnerability|formal proof|adversarial)\b",
    r"\b(architecture|design system|scale to|distributed)\b",
    r"\b(optimize.*\bO\(|complexity analysis|prove that)\b",
]
STANDARD_SIGNALS = [
    r"\b(design|implement|algorithm|refactor|debug|explain .{20,})\b",
    r"\b(compare|trade-off|pros and cons|when should)\b",
]
LIGHT_SIGNALS = [
    r"\b(write a (function|class|snippet)|summarize|translate)\b",
    r"\b(what is|how do I|example of)\b",
]

def classify_effort(prompt: str) -> Effort:
    p = prompt.lower()
    for pattern in DEEP_SIGNALS:
        if re.search(pattern, p):
            return Effort.DEEP
    for pattern in STANDARD_SIGNALS:
        if re.search(pattern, p):
            return Effort.STANDARD
    for pattern in LIGHT_SIGNALS:
        if re.search(pattern, p):
            return Effort.LIGHT
    # Default: no thinking for very short or unrecognised prompts
    return Effort.NONE if len(prompt) < 80 else Effort.LIGHT

def auto_call(prompt: str) -> tuple[str, Effort]:
    effort = classify_effort(prompt)
    return call(prompt, effort), effort

answer, used_effort = auto_call("Design a circuit-breaker pattern for microservices.")
print(f"Effort used: {used_effort.name} ({int(used_effort)} budget tokens)")
print(answer)

import hashlib
from functools import lru_cache

# Normalise prompt for cache key (strip whitespace, lowercase)
def _cache_key(prompt: str, effort: Effort) -> str:
    h = hashlib.sha256(prompt.strip().lower().encode()).hexdigest()[:16]
    return f"{effort.name}:{h}"

_cache: dict[str, str] = {}

def cached_call(prompt: str, effort: Effort) -> str:
    # Serve from cache if we have same or higher effort tier cached
    for tier in [e for e in Effort if e >= effort]:
        key = _cache_key(prompt, tier)
        if key in _cache:
            return _cache[key]   # cached answer meets or exceeds required effort

    answer = call(prompt, effort)
    _cache[_cache_key(prompt, effort)] = answer
    return answer

import sys

def streamed_call(prompt: str, effort: Effort) -> str:
    """Stream a call, showing effort-appropriate progress indicators."""
    if effort == Effort.NONE:
        # Simple streaming, no thinking indicator needed
        parts = []
        with client.messages.stream(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            messages=[{"role": "user", "content": prompt}],
        ) as stream:
            for text in stream.text_stream:
                sys.stdout.write(text)
                sys.stdout.flush()
                parts.append(text)
        print()
        return "".join(parts)

    # For thinking-enabled tiers, show phase indicator
    labels = {Effort.LIGHT: "Checking", Effort.STANDARD: "Reasoning", Effort.DEEP: "Analysing"}
    label = labels.get(effort, "Thinking")

    parts = []
    in_thinking = False
    with client.messages.stream(
        model="claude-sonnet-4-6",
        max_tokens=int(effort) + 4096,
        thinking={"type": "enabled", "budget_tokens": int(effort)},
        messages=[{"role": "user", "content": prompt}],
    ) as stream:
        for event in stream:
            t = getattr(event, "type", None)
            if t == "content_block_start":
                block_type = event.content_block.type
                if block_type == "thinking":
                    in_thinking = True
                    sys.stdout.write(f"[{label}...]")
                    sys.stdout.flush()
                elif block_type == "text" and in_thinking:
                    sys.stdout.write("\r" + " " * 20 + "\r")  # clear indicator
                    in_thinking = False
            elif t == "content_block_delta":
                if not in_thinking and hasattr(event.delta, "text"):
                    sys.stdout.write(event.delta.text)
                    sys.stdout.flush()
                    parts.append(event.delta.text)
    print()
    return "".join(parts)

import statistics
import time

def benchmark_tiers(
    prompts: list[str],
    tiers: list[Effort],
    quality_fn,           # callable(prompt, answer) -> float
) -> dict[str, dict]:
    results = {tier.name: {"latencies": [], "scores": []} for tier in tiers}

    for prompt in prompts:
        for tier in tiers:
            start = time.monotonic()
            answer = call(prompt, tier)
            elapsed = time.monotonic() - start
            score = quality_fn(prompt, answer)
            results[tier.name]["latencies"].append(elapsed)
            results[tier.name]["scores"].append(score)

    summary = {}
    for name, data in results.items():
        summary[name] = {
            "avg_latency_s": round(statistics.mean(data["latencies"]), 2),
            "p95_latency_s": round(sorted(data["latencies"])[int(len(data["latencies"]) * 0.95)], 2),
            "avg_quality": round(statistics.mean(data["scores"]), 3),
        }
    return summary

